## 2️⃣ C++ wrapper implementation – **`blocksci_c.cpp`**

```cpp
/*=====================================================================
 * blocksci_c.cpp
 *   C++ implementation of the C API declared in blocksci_c.h.
 *
 *   Build command (example):
 *       c++ -std=c++20 -fPIC -shared -I/path/to/blocksci/include \
 *           -o libblocksci_c.so blocksci_c.cpp -lblocksci
 *
 *   The file is deliberately self‑contained – it only depends on the
 *   public BlockSci headers.  If you need extra fields, extend the
 *   blocksci_block_t struct in the header and add the corresponding
 *   assignments below.
 *====================================================================*/

#include "blocksci_c.h"

#include <blocksci/chain/chain.hpp>          // <-- real BlockSci include
#include <blocksci/chain/block.hpp>
#include <blocksci/exception.hpp>

#include <cstring>   // memcpy, strlen
#include <cstdlib>   // malloc, free
#include <mutex>     // for thread‑safe lazy init (optional)

/* --------------------------------------------------------------------
 * The opaque handle definitions – they are just thin wrappers around
 * the real BlockSci objects.
 * -------------------------------------------------------------------- */
struct blocksci_iterator_s {
    blocksci::Chain chain;               // owns the chain data
    blocksci::BlockIterator it;          // current iterator
    uint64_t total_blocks;               // cached block count
};

/* --------------------------------------------------------------------
 * Helper: convert a native BlockSci block into the public POD struct.
 * -------------------------------------------------------------------- */
static inline void fill_block_pod(
        const blocksci::Block &src,
        blocksci_block_t &dst)
{
    dst.height    = src.height();
    dst.tx_count  = static_cast<uint32_t>(src.tx_count());

    // BlockSci stores the hash as a 32‑byte array; we expose a hex string.
    // The string is allocated once per iterator and lives as long as the
    // iterator (no per‑block allocation, which is critical for hot loops).
    static thread_local char hash_hex[65];
    src.hash().to_hex(hash_hex);
    dst.hash_hex = hash_hex;

    dst.timestamp = src.timestamp();
}

/* --------------------------------------------------------------------
 * Create a new iterator.
 * -------------------------------------------------------------------- */
blocksci_iterator_t *blocksci_iterator_new(const char *chain_path)
{
    if (!chain_path) {
        errno = BLOCKSCI_ERR_INVALID_ARGUMENT;
        return nullptr;
    }

    try {
        auto *handle = new blocksci_iterator_t;
        // The Chain constructor loads the deployment directory.
        handle->chain = blocksci::Chain(chain_path);
        handle->it    = handle->chain.begin();
        handle->total_blocks = handle->chain.size();
        return handle;
    } catch (const blocksci::OpenError &) {
        errno = BLOCKSCI_ERR_OPEN;
        return nullptr;
    } catch (const std::exception &) {
        errno = BLOCKSCI_ERR_ITERATOR;
        return nullptr;
    }
}

/* --------------------------------------------------------------------
 * Destroy the iterator and free all resources.
 * -------------------------------------------------------------------- */
void blocksci_iterator_free(blocksci_iterator_t *it)
{
    delete it;   // RAII cleans up the Chain object
}

/* --------------------------------------------------------------------
 * Walk the chain, invoking the user callback for each block.
 *
 * This is the performance‑critical hot path.  The only work done per
 * iteration is:
 *   • copy a few scalar fields into a POD struct (in registers)
 *   • call the user function pointer
 *
 * No heap allocation, no virtual dispatch, no exception handling.
 * -------------------------------------------------------------------- */
int blocksci_iterator_for_each(
        blocksci_iterator_t *handle,
        blocksci_block_callback cb,
        void *user_data)
{
    if (!handle || !cb) {
        errno = BLOCKSCI_ERR_INVALID_ARGUMENT;
        return BLOCKSCI_ERR_INVALID_ARGUMENT;
    }

    /* The iterator type returned by BlockSci is a forward iterator.
     * We simply loop until we hit .end().
     */
    for (auto it = handle->chain.begin(); it != handle->chain.end(); ++it) {
        blocksci_block_t block_pod;
        fill_block_pod(*it, block_pod);

        int rc = cb(&block_pod, user_data);
        if (rc != 0) {
            // Propagate the non‑zero value (user‑defined abort code)
            errno = BLOCKSCI_ERR_CALLBACK;
            return rc;
        }
    }
    return BLOCKSCI_OK;
}

/* --------------------------------------------------------------------
 * Return the cached block count.
 * -------------------------------------------------------------------- */
uint64_t blocksci_chain_block_count(const blocksci_iterator_t *handle)
{
    if (!handle) {
        errno = BLOCKSCI_ERR_INVALID_ARGUMENT;
        return 0;
    }
    return handle->total_blocks;
}

/* --------------------------------------------------------------------
 * Optional: expose a "visit all blocks" convenience macro for C users.
 * -------------------------------------------------------------------- */
#ifdef __cplusplus
extern "C" {
#endif

/* The header already declared the functions; the definitions above
 * satisfy the C linkage requirements.  No extra symbols are needed. */

#ifdef __cplusplus
} /* extern "C" */
#endif
```

